from haystack import Pipeline
from haystack.components.builders import CustomComponent
from vex import VexClient

class VexComplianceComponent(CustomComponent):
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")

    def run(self, query: str, retrieved_docs: list, generated_answer: str):
        # Check retriever relevance
        relevance_score = self.vex.evaluate_retrieval(query, retrieved_docs)
        if relevance_score < 0.8:
            raise ValueError("Retriever returned irrelevant documents")

        # Check generator faithfulness
        faithfulness = self.vex.evaluate_faithfulness(generated_answer, retrieved_docs)
        if faithfulness < 0.9:
            raise ValueError("Generator hallucinated beyond context")

        # SOX/SEC disclaimer injection
        if 'advice' in query.lower():
            generated_answer += "\n\n*This is not personalized financial advice. Consult a licensed advisor.*"

        return {"approved_answer": generated_answer}

# Usage in pipeline
vex_guard = VexComplianceComponent()
pipeline.add_component("vex_guard", vex_guard)

from haystack.components.builders import CustomComponent
import re
from vex import VexClient

class PCIRedactionComponent(CustomComponent):
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")
        self.card_pattern = re.compile(r'\b\d{4}-\d{4}-\d{4}-\d{4}\b')

    def run(self, documents: list):
        redacted_docs = []
        for doc in documents:
            # Vex PII detection
            pii_alerts = self.vex.scan_pii(doc.content)
            if pii_alerts:
                doc.content = self.card_pattern.sub("[CARD_NUMBER_REDACTED]", doc.content)
                # Log for PCI audit trail
                self.vex.log_compliance_event("PCI_redaction", pii_alerts)
            redacted_docs.append(doc)
        return {"documents": redacted_docs}

pipeline.add_component("pci_redactor", PCIRedactionComponent())

from haystack.components.builders import CustomComponent
from vex import VexClient

class GDPRMinimizeComponent(CustomComponent):
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")

    def run(self, query: str, candidate_docs: list, user_consent: str):
        filtered_docs = []
        for doc in candidate_docs:
            # Verify data relevance to query
            relevance = self.vex.semantic_similarity(query, doc.content)
            if relevance > 0.75:
                # Check consent scope
                consent_check = self.vex.validate_consent(user_consent, doc.metadata.get("data_category"))
                if consent_check:
                    filtered_docs.append(doc)
                else:
                    self.vex.log_gdpr_violation("consent_denied", doc.metadata)
        if len(filtered_docs) == 0:
            raise ValueError("No consented relevant documents found")
        return {"approved_docs": filtered_docs}

pipeline.connect("retriever", "gdpr_filter")
